// Parse Google Sheet CSV + UF actual. Devuelve info completa del lote solicitado
// o lista completa de disponibles si no viene numero.
// Campos por lote: numero, estado, tamano_m2, precio_contado, descuento_pct,
//                  precio_credito, pie_minimo, cuota_mensual_clp, cuota_mensual_uf.

const uf = $json;
const ufValor = uf && uf.serie && uf.serie[0] && typeof uf.serie[0].valor === 'number'
  ? uf.serie[0].valor
  : null;
const ufFecha = uf && uf.serie && uf.serie[0] ? uf.serie[0].fecha : null;

const sheetItem = $('Fetch Google Sheet CSV').first().json;
const csvText = ((sheetItem && (sheetItem.data || sheetItem.body)) || '').toString();
if (!csvText || csvText.length < 100) {
  return [{ json: {
    ok: false,
    error: 'csv_fetch_failed',
    tool_output_text: 'No pude consultar el inventario en este momento. Deja que Diego te confirme por WhatsApp.',
  } }];
}

const input = $('Execute Workflow Trigger').first().json || {};
const numero = (input.numero ?? '').toString().trim().toUpperCase();

// CSV parser (maneja comillas y comas dentro de campos)
function parseCsv(text) {
  const rows = [];
  let row = [];
  let field = '';
  let inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const c = text[i];
    if (c === '"') {
      if (inQuotes && text[i + 1] === '"') { field += '"'; i++; }
      else { inQuotes = !inQuotes; }
    } else if (c === ',' && !inQuotes) {
      row.push(field); field = '';
    } else if ((c === '\n' || c === '\r') && !inQuotes) {
      if (c === '\r' && text[i + 1] === '\n') i++;
      row.push(field); rows.push(row); row = []; field = '';
    } else {
      field += c;
    }
  }
  if (field.length || row.length) { row.push(field); rows.push(row); }
  return rows;
}

const parseMoney = (s) => {
  if (!s) return null;
  const t = s.toString();
  if (t.includes('#DIV') || t.includes('#REF') || t.includes('#VALUE')) return null;
  const cleaned = t.replace(/[^0-9]/g, '');
  return cleaned ? parseInt(cleaned, 10) : null;
};
const parseSize = (s) => {
  if (!s) return null;
  const cleaned = s.toString().replace(/[^0-9]/g, '');
  return cleaned ? parseInt(cleaned, 10) : null;
};
const parseIntSafe = (s) => {
  if (!s) return null;
  const cleaned = s.toString().replace(/[^0-9]/g, '');
  return cleaned ? parseInt(cleaned, 10) : null;
};
const normalizeEstado = (raw) => {
  const e = (raw || '').toString().trim().toLowerCase();
  if (e.startsWith('disponi')) return 'disponible';
  if (e.startsWith('reserv')) return 'reservado';
  if (e.startsWith('vendi')) return 'vendido';
  return e || 'desconocido';
};

const clpToUf = (clp) => {
  if (clp === null || !ufValor) return null;
  return Math.round((clp / ufValor) * 100) / 100;
};

const rows = parseCsv(csvText);
const parcelas = [];
for (const r of rows) {
  if (!r || r.length < 3) continue;
  const lote = (r[1] || '').toString().trim();
  if (!/^(\d{1,3}|B\d{1,2})$/i.test(lote)) continue;
  const cuotaClp = parseMoney(r[11]);
  parcelas.push({
    numero: lote.toUpperCase(),
    destacada: ((r[0] || '').toString().trim() === '⭐'),
    estado: normalizeEstado(r[2]),
    tamano_m2: parseSize(r[3]),
    precio_contado: parseMoney(r[6]),
    descuento_pct: parseIntSafe(r[7]),
    precio_credito: parseMoney(r[9]),
    pie_minimo_50pct: parseMoney(r[10]),
    cuota_mensual_clp: cuotaClp,
    cuota_mensual_uf: clpToUf(cuotaClp),
  });
}

const fmtClp = (n) => (n === null || n === undefined) ? '—' : `$${n.toLocaleString('es-CL')}`;
const fmtUf = (n) => (n === null || n === undefined) ? '—' : `${n.toFixed(2)} UF`;

function lotText(p) {
  if (p.estado === 'disponible') {
    const dest = p.destacada ? ' ⭐' : '';
    return `Parcela ${p.numero}${dest} · ${p.tamano_m2} m² · disponible · contado ${fmtClp(p.precio_contado)} (dcto ${p.descuento_pct || 0}%) · crédito ${fmtClp(p.precio_credito)} con 50% pie ${fmtClp(p.pie_minimo_50pct)} + 36 cuotas de ${fmtUf(p.cuota_mensual_uf)} (~${fmtClp(p.cuota_mensual_clp)} al valor UF de hoy).`;
  }
  if (p.estado === 'reservado') return `Parcela ${p.numero} · ${p.tamano_m2} m² · reservada.`;
  if (p.estado === 'vendido') return `Parcela ${p.numero} · ${p.tamano_m2} m² · vendida.`;
  return `Parcela ${p.numero} · estado no definido.`;
}

// Modo 1: consulta puntual por numero
if (numero) {
  const match = parcelas.find(p => p.numero === numero);
  if (!match) {
    return [{ json: {
      ok: false,
      query: { numero },
      uf_valor_clp: ufValor,
      uf_fecha: ufFecha,
      tool_output_text: `No encuentro la parcela ${numero} en el inventario. Las numeradas van del 1 al 74 y hay lotes B1 al B20 de ampliación.`,
    } }];
  }
  return [{ json: {
    ok: true,
    query: { numero },
    uf_valor_clp: ufValor,
    uf_fecha: ufFecha,
    parcela: match,
    tool_output_text: lotText(match),
  } }];
}

// Modo 2: sin numero → lista todos los disponibles
const disponibles = parcelas.filter(p => p.estado === 'disponible');
// Orden: destacadas primero, luego por precio contado asc (null al final)
disponibles.sort((a, b) => {
  if (a.destacada !== b.destacada) return a.destacada ? -1 : 1;
  const pa = a.precio_contado ?? Infinity;
  const pb = b.precio_contado ?? Infinity;
  if (pa !== pb) return pa - pb;
  return a.numero.localeCompare(b.numero, 'es', { numeric: true });
});

if (disponibles.length === 0) {
  return [{ json: {
    ok: true,
    query: {},
    uf_valor_clp: ufValor,
    uf_fecha: ufFecha,
    total_disponibles: 0,
    parcelas: [],
    tool_output_text: 'En este momento no tengo parcelas disponibles. ¿Te aviso cuando entre alguna?',
  } }];
}

const lines = disponibles.map(lotText).join('\n');
const text = `Tengo ${disponibles.length} parcelas disponibles ahora:\n${lines}`;

return [{ json: {
  ok: true,
  query: {},
  uf_valor_clp: ufValor,
  uf_fecha: ufFecha,
  total_disponibles: disponibles.length,
  parcelas: disponibles,
  tool_output_text: text,
} }];
